#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16

// Macros for indexing matrix elements
#define AA(i,j) a[(offset)*size + (i)*size + (j) + (offset)]
#define BB(i,j) a[(i)*size + (j)]

// Kernel for diagonal block LU decomposition
__kernel void lud_diagonal(__global float* a, __local float* shared_mem, int size, int offset)
{
    int i = get_global_id(0);
    if (i >= BLOCK_SIZE) return;

    // Process diagonal block
    for (int j = i; j < BLOCK_SIZE; j++) {
        float sum = AA(i,j);
        for (int k = 0; k < i; k++) {
            sum -= AA(i,k) * AA(k,j);
        }
        AA(i,j) = sum;
    }

    float temp = 1.0f / AA(i,i);

    for (int j = i+1; j < BLOCK_SIZE; j++) {
        float sum = AA(j,i);
        for (int k = 0; k < i; k++) {
            sum -= AA(j,k) * AA(k,i);
        }
        AA(j,i) = sum * temp;
    }
}

// Kernel for perimeter update (row and column blocks)
__kernel void lud_perimeter(__global float* a, __local float* shared_l, __local float* shared_u_l, __local float* shared_u_r, int size, int offset)
{
    int gid = get_global_id(0);
    int block_per_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    int total_perimeter_blocks = block_per_row * 2;
    if (gid >= total_perimeter_blocks) return;

    int block_idx = gid;
    int i_global = offset;
    int j_global = offset;

    // Load diagonal block into shared_l
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            shared_l[i * BLOCK_SIZE + j] = AA(i,j);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (block_idx < block_per_row) {
        // Update perimeter row blocks to the right
        j_global += BLOCK_SIZE * (block_idx + 1);

        for (int j = 0; j < BLOCK_SIZE; j++) {
            for (int i = 0; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (int k = 0; k < i; k++) {
                    sum += shared_l[i * BLOCK_SIZE + k] * a[(i_global + k)*size + (j_global + j)];
                }
                int i_here = i_global + i;
                int j_here = j_global + j;
                a[i_here*size + j_here] = a[i_here*size + j_here] - sum;
            }
        }
    } else {
        // Update perimeter column blocks below
        int col_block_idx = block_idx - block_per_row;
        i_global += BLOCK_SIZE * (col_block_idx + 1);

        float temp_diag[BLOCK_SIZE];
        for (int i = 0; i < BLOCK_SIZE; i++) {
            temp_diag[i] = 1.0f / AA(i,i);
        }

        for (int i = 0; i < BLOCK_SIZE; i++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (int k = 0; k < j; k++) {
                    sum += a[(i_global + i)*size + (j_global + k)] * shared_l[k * BLOCK_SIZE + j];
                }
                int i_here = i_global + i;
                int j_here = j_global + j;
                a[i_here*size + j_here] = (a[i_here*size + j_here] - sum) * temp_diag[j];
            }
        }
    }
}

// Kernel for internal block update
__kernel void lud_internal(__global float* a, __local float* shared_u, __local float* shared_l, int size, int offset)
{
    int local_x = get_local_id(0);
    int local_y = get_local_id(1);
    int group_x = get_group_id(0);
    int group_y = get_group_id(1);

    int block_per_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    if (group_x >= block_per_row || group_y >= block_per_row) return;

    int i_global = offset + BLOCK_SIZE * (group_y + 1);
    int j_global = offset + BLOCK_SIZE * (group_x + 1);

    // Load top block (perimeter row) into shared_u
    shared_u[local_y*BLOCK_SIZE + local_x] = a[(offset + local_y)*size + (j_global + local_x)];
    // Load left block (perimeter column) into shared_l
    shared_l[local_y*BLOCK_SIZE + local_x] = a[(i_global + local_y)*size + (offset + local_x)];

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += shared_l[local_y*BLOCK_SIZE + k] * shared_u[k*BLOCK_SIZE + local_x];
    }

    int idx_i = i_global + local_y;
    int idx_j = j_global + local_x;

    a[idx_i*size + idx_j] -= sum;
}
